import{_ as s,o as a,c as e,a5 as t}from"./chunks/framework.B5tqjWbr.js";const u=JSON.parse('{"title":"概念：连续导通模式（continuous conduction mode / CCM）与断续导通模式（discontinuous conduction mode / DCM）","description":"","frontmatter":{"date":"2026-06-21T00:00:00.000Z","category":"电源控制","source":"power","visibility":"public","title":"概念：连续导通模式（continuous conduction mode / CCM）与断续导通模式（discontinuous conduction mode / DCM）","tags":["power-electronics"],"status":"learning","summary":"连续导通模式（continuous conduction mode / CCM）指电感电流（inductor current）在一个开关周期内始终大于 0。断续导通模式（discontinuous conduction mode / DCM）指电感电流在一个开关周期内会降到 0，并保持一段零电流时间。"},"headers":[],"relativePath":"content/power/concepts/power-electronics/ccm-dcm.md","filePath":"content/power/concepts/power-electronics/ccm-dcm.md","lastUpdated":null}'),n={name:"content/power/concepts/power-electronics/ccm-dcm.md"};function o(l,i,c,p,d,h){return a(),e("div",null,[...i[0]||(i[0]=[t(`<h1 id="概念-连续导通模式-continuous-conduction-mode-ccm-与断续导通模式-discontinuous-conduction-mode-dcm" tabindex="-1">概念：连续导通模式（continuous conduction mode / CCM）与断续导通模式（discontinuous conduction mode / DCM） <a class="header-anchor" href="#概念-连续导通模式-continuous-conduction-mode-ccm-与断续导通模式-discontinuous-conduction-mode-dcm" aria-label="Permalink to &quot;概念：连续导通模式（continuous conduction mode / CCM）与断续导通模式（discontinuous conduction mode / DCM）&quot;">​</a></h1><h2 id="_1-它是什么" tabindex="-1">1. 它是什么 <a class="header-anchor" href="#_1-它是什么" aria-label="Permalink to &quot;1. 它是什么&quot;">​</a></h2><p>连续导通模式（continuous conduction mode / CCM）指电感电流（inductor current）在一个开关周期内始终大于 0。断续导通模式（discontinuous conduction mode / DCM）指电感电流在一个开关周期内会降到 0，并保持一段零电流时间。</p><p>对 Boost 升压变换器（Boost converter）来说，CCM 和 DCM 不是两个不同电路，而是同一个电路在不同电感、负载、占空比和开关频率条件下表现出的两种工作状态。</p><h2 id="_2-ups-为什么需要它" tabindex="-1">2. UPS 为什么需要它 <a class="header-anchor" href="#_2-ups-为什么需要它" aria-label="Permalink to &quot;2. UPS 为什么需要它&quot;">​</a></h2><p>不间断电源（uninterruptible power supply / UPS）里的功率因数校正（power factor correction / PFC）、电池升压直流-直流变换（direct current to direct current conversion / DC-DC）和辅助电源，都可能遇到电感电流是否断续的问题。</p><ul><li>控制模型不同：CCM 常用平均模型更直观，DCM 的输入输出关系会受负载影响。</li><li>采样解释不同：电流采样如果落在零电流段，固件看到的不是“控制坏了”，而可能是工作模式已进入 DCM。</li><li>保护逻辑不同：轻载 DCM 很常见，不应误判为开路；重载下进入异常电流形态则要警惕电感饱和、驱动异常或采样异常。</li><li>噪声和效率不同：DCM 可能带来更大的峰值电流和电磁干扰（electromagnetic interference / EMI），但轻载控制可能更容易。</li></ul><h2 id="_3-物理直觉" tabindex="-1">3. 物理直觉 <a class="header-anchor" href="#_3-物理直觉" aria-label="Permalink to &quot;3. 物理直觉&quot;">​</a></h2><p>电感像“电流惯性元件”。开关导通时，Boost 电感两端电压约为输入电压，电感电流上升；开关关断时，电感把能量送到输出，电感电流下降。</p><p>如果负载重、电感大、开关周期短，电感还没来得及把电流降到 0，下一个周期已经开始，这就是 CCM。</p><p>如果负载轻、电感小、开关周期长，电感在关断阶段把能量放完，电流降到 0，并等待下一个周期，这就是 DCM。</p><h2 id="_4-数学形式" tabindex="-1">4. 数学形式 <a class="header-anchor" href="#_4-数学形式" aria-label="Permalink to &quot;4. 数学形式&quot;">​</a></h2><p>理想 Boost 在 CCM 下的电压关系是：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Vout = Vin / (1 - D)</span></span></code></pre></div><p>其中 <code>D</code> 是占空比（duty cycle / D）。</p><p>电感电流纹波可粗略估算为：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Delta_IL_on = Vin * D / (L * fsw)</span></span></code></pre></div><p>其中 <code>L</code> 是电感量（inductance），<code>fsw</code> 是开关频率（switching frequency）。当平均电感电流小于纹波的一半时，电流就容易碰到 0：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>IL_avg &lt;= Delta_IL / 2  -&gt;  容易进入 DCM</span></span></code></pre></div><p>这个判断是工程直觉，不是完整设计公式。真实边界还会受输出电压、损耗、采样方式和控制策略影响。</p><h2 id="_5-仿真观察" tabindex="-1">5. 仿真观察 <a class="header-anchor" href="#_5-仿真观察" aria-label="Permalink to &quot;5. 仿真观察&quot;">​</a></h2><p>使用脚本：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>simulations/python/boost_ccm_dcm.py</span></span></code></pre></div><p>默认参数偏向 DCM：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Vin=48 V, D=0.45, L=100 uH, C=470 uF, R=500 ohm, fsw=20 kHz</span></span></code></pre></div><p>观察重点：</p><ul><li>电感电流曲线是否碰到红色零电流线。</li><li>图标题中的模式判断是 CCM 还是 DCM。</li><li>参数框里的 <code>Tail zero fraction</code> 是否明显大于 0。</li><li>DCM 时最终输出电压不应机械套用 CCM 公式。</li></ul><h2 id="_6-固件落地" tabindex="-1">6. 固件落地 <a class="header-anchor" href="#_6-固件落地" aria-label="Permalink to &quot;6. 固件落地&quot;">​</a></h2><p>固件里不会直接拿示波器波形“看模式”，而是从采样值和状态判断：</p><ul><li>电流采样接近 0 且持续出现在关断后段，可作为 DCM 迹象。</li><li>轻载时进入 DCM 可能是正常状态，不能直接报故障。</li><li>电流环控制器在 DCM 下的等效对象变化，比例积分控制器（proportional-integral controller / PI）的参数和限幅要谨慎。</li><li>保护逻辑要区分“轻载零电流”和“采样断线、驱动缺失、开关不开通”等故障。</li></ul><h2 id="_7-常见误解" tabindex="-1">7. 常见误解 <a class="header-anchor" href="#_7-常见误解" aria-label="Permalink to &quot;7. 常见误解&quot;">​</a></h2><ul><li><p>错误理解：CCM 一定好，DCM 一定坏。<br> 正确理解：它们是不同工况。重载功率级常希望 CCM 便于控制和降低峰值电流，轻载 DCM 很常见。</p></li><li><p>错误理解：只要占空比固定，Boost 输出一定等于 <code>Vin / (1 - D)</code>。<br> 正确理解：这个公式主要适用于理想 CCM 稳态。DCM 下输出还与负载、电感、频率有关。</p></li><li><p>错误理解：电感电流碰到 0 就说明电路断了。<br> 正确理解：轻载、小电感、高输出电压条件下，电感能量可能在本周期内释放完，这是 DCM 的正常现象。</p></li><li><p>错误理解：软件不需要关心 CCM/DCM。<br> 正确理解：采样时刻、控制模型、保护阈值和轻载策略都会受工作模式影响。</p></li></ul><h2 id="_8-一个仿真任务" tabindex="-1">8. 一个仿真任务 <a class="header-anchor" href="#_8-一个仿真任务" aria-label="Permalink to &quot;8. 一个仿真任务&quot;">​</a></h2><p>运行：</p><div class="language-powershell vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">powershell</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">python simulations\\python\\boost_ccm_dcm.py </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">--</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">inductance </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">100e</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">6</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> --</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">resistance </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">500</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> --</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">output simulations\\results\\boost_ccm_dcm_dcm.png </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">--</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">no</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">open</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">python simulations\\python\\boost_ccm_dcm.py </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">--</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">inductance </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">1e</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">3</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> --</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">resistance </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">50</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> --</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">output simulations\\results\\boost_ccm_dcm_ccm.png </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">--</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">no</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">open</span></span></code></pre></div><p>观察两张图中的电感电流是否碰到零电流线，并记录 <code>Tail min IL</code>、<code>Tail zero fraction</code> 和模式判断。</p><h2 id="_9-验收标准" tabindex="-1">9. 验收标准 <a class="header-anchor" href="#_9-验收标准" aria-label="Permalink to &quot;9. 验收标准&quot;">​</a></h2><ul><li>能用一句话区分 CCM 和 DCM。</li><li>能在仿真图上指出电感电流是否碰到 0。</li><li>能说明为什么轻载、小电感更容易进入 DCM。</li><li>能解释为什么 DCM 下不能直接套用理想 CCM 公式。</li><li>能说出固件采样和保护逻辑为什么需要知道 CCM/DCM。</li></ul><h2 id="_10-复盘问题" tabindex="-1">10. 复盘问题 <a class="header-anchor" href="#_10-复盘问题" aria-label="Permalink to &quot;10. 复盘问题&quot;">​</a></h2><ul><li><code>boost_ccm_dcm_dcm.png</code> 里电感电流为 0 的区间对应开关导通、关断，还是关断后的等待？</li><li><code>boost_ccm_dcm_ccm.png</code> 里 <code>Tail min IL</code> 为什么能支持 CCM 判断？</li><li>如果把 <code>--resistance 500</code> 改成 <code>--resistance 50</code>，负载变重后为什么更不容易 DCM？</li></ul><h2 id="_11-导师问题" tabindex="-1">11. 导师问题 <a class="header-anchor" href="#_11-导师问题" aria-label="Permalink to &quot;11. 导师问题&quot;">​</a></h2><ul><li>我用 <code>boost_ccm_dcm.py --inductance 100e-6 --resistance 500</code> 得到 DCM 波形，电感电流有明显零电流段。公司产品里轻载 PFC 或电池 DC-DC 是否允许类似零电流段？</li><li>我用 <code>--inductance 1e-3 --resistance 50</code> 得到 CCM 波形。实际项目里判断 CCM/DCM 主要看示波器电流探头，还是固件里的采样统计量？</li><li>如果固件在关断后段采到接近 0 A 的电感电流，公司通常如何区分正常 DCM、采样噪声和电流采样故障？</li></ul>`,42)])])}const k=s(n,[["render",o]]);export{u as __pageData,k as default};
